<script setup>
	import {
		onReachBottom,
		onPullDownRefresh,
		onPageScroll
	} from '@dcloudio/uni-app'
	import {
		computed,
		reactive,
		ref,
	} from 'vue';
	let imgs = reactive([]);
	let refresh;
	// current:当前点击按钮的内容
	let current=ref();
	let animals=[
		{name:'全部',value:'all'},
		{name:'猫猫',value:'cat'},
		{name:'狗狗',value:'dog'}
	];
	// value:显示内容
	let values=computed(()=>animals.map(item=>item.name));
	let type=ref('all');
	//预览
	function showImage(index) {
		let urls = imgs.map(item => item.url);
		uni.previewImage({
			current: index,
			urls
		})
	};

	function Get_imgs() {
		uni.request({
			url: 'https://tea.qingnian8.com/tools/petShow',
			data: {
				size: 5,
				type:type.value
			},
			header: {
				'access-key': "okugls"
			},
			success: (res) => {
				//console.log(res.data);
				refresh = res.data.errCode;
				imgs.push(...res.data.data)
				//console.log(imgs);
			}
		});
	};
	Get_imgs();
	//触底刷新
	onReachBottom(() => {
		
		Get_imgs();
	})
	//监听页面滚动
	onPageScroll((e)=>{
		
	})
	function go_Top() {
		uni.pageScrollTo({
			scrollTop: 0,
			duration: 200
		});
	}
	//下拉刷新
	onPullDownRefresh(() => {
		Get_imgs();
		if (refresh == 0) {
			imgs.splice(0, imgs.length);
			uni.showToast({
				title: '已刷新', // 提示的内容
				icon: 'success', // 使用内置的成功图标
				duration: 1000 // 弹框显示持续2秒
			});
			uni.stopPullDownRefresh();
		} else {
			uni.showToast({
				title: '加载失败', // 提示的内容
				icon: 'error', // 使用内置的成功图标
				duration: 1000 // 弹框显示持续2秒
			});
			uni.stopPullDownRefresh();
		}
	})
	//分类刷新
	function onClickItem(e){
		current=animals[e.currentIndex].value;
		imgs.splice(0,imgs.length-1);
		type.value=current;
		Get_imgs();
	}
</script>

<template>
	<view>
		<view class="top">
			<uni-segmented-control  :values="values" :current="current"  @clickItem="onClickItem" styleType="button" activeColor="skyblue"></uni-segmented-control>
		</view>
		<view class="contain">
			<view class="go_Top" @click="go_Top()">
				<text>顶部</text>
			</view>
			<view class="box" v-for="(item,index) in imgs" :key="item._id">
				<image :src="item.url" mode="scaleToFill" @click="showImage(index)"></image>
				<text>{{item.content}}</text>
				<text>——{{item.author}}</text>
			</view>
			<view>
				<uni-load-more status="loading"></uni-load-more>
			</view>
		</view>
	</view>
</template>

<style lang="scss">
	.contain {
		width: 100%;
	}
	.top{
		width: 650rpx;
		margin: auto;
		margin-top: 30rpx;
	}
	.box {
		width: 650rpx;
		height: 650rpx;
		margin: 5% 7%;
		border-radius: 8px;
		background-color: whitesmoke;
		box-shadow: 10px 10px 5px #888888;
		z-index: 5;

		image {
			width: 100%;
			height: 81%;
			border-radius: 8px 8px 0px 0px;
		}
	}

	text {
		display: block;
		font-size: 30rpx;
		margin-left: 20rpx;
	}

	text:nth-child(3) {
		color: skyblue;
		margin-left: 400rpx;
	}

	.go_Top {
		width: 70rpx;
		height: 70rpx;
		background-color: whitesmoke;
		border-radius: 50%;
		position: fixed;
		left: 85%;
		top: 50%;
		z-index: 10;

		image {
			width: 80%;
			height: 80%;
		}
	}
</style>